/** biome-ignore-all lint/style/noNonNullAssertion: value is properly checked */
import {
  type EntityId,
  getShoppingListsChannelName,
  type JsPostgresAction,
  type NetworkError,
  type Result,
  type ShoppingList,
  type ShoppingListClient,
  type Subscription,
} from "@bill/Bill-shoppingList";

import type { Channels, ClientOptionsWithAutoListener } from "~/composables/types";
import { useKtClientData } from "~/composables/useKtClientData";
import { useOptimisticUpdatedList } from "~/composables/useOptimisticUpdatedList";
import { useShoppingListClient } from "~/composables/useShoppingListClient";
import { getChannelActionFrom } from "~/utils/channelAction";
import { ktToJs } from "~/utils/ktToJs";
import { readResponse } from "~/utils/readResponse";

type ListenerType = "shoppingListsChanges";

type ShoppingListsOptions = ClientOptionsWithAutoListener<
  ShoppingList[],
  ShoppingListClient,
  ListenerType[]
>;

export function useShoppingLists(options?: ShoppingListsOptions) {
  const { client, useAutoListenFor, ...asyncDataOptions } = options ?? {};

  const channelName = computed(() => getShoppingListsChannelName());
  const loading = ref(false);
  const error = ref<Error | null>(null);
  const channel = ref<Channels>(new Map() as Channels);

  const shoppingListClient = client ?? useShoppingListClient();

  const {
    data,
    pending,
    error: fetchError,
    refresh,
  } = useKtClientData(
    "shoppingLists",
    () => shoppingListClient.getShoppingListsAsync(),
    asyncDataOptions,
  );

  const {
    listToSync: shoppingLists,
    getItem: __getList,
    upsertItem: __upsertList,
    deleteItem: __deleteList,
    releaseAction,
    isActionBlocked,
    blockAction,
  } = useOptimisticUpdatedList(data);

  async function handleChanges(
    payload:
      | JsPostgresAction<ShoppingList, null>
      | JsPostgresAction<ShoppingList, EntityId>
      | JsPostgresAction<null, EntityId>,
  ) {
    console.log("useShoppingLists #handleChanges->");
    try {
      const jsPayload = ktToJs(payload);

      // biome-ignore lint/suspicious/noExplicitAny: fix after fixing ktToJs
      const channelAction = getChannelActionFrom(jsPayload as any);
      const isBlocked = isActionBlocked(
        jsPayload.record?.id ?? jsPayload.oldRecord?.id ?? -1,
        channelAction,
      );

      if (isBlocked) {
        return;
      }

      switch (channelAction) {
        case "insert": {
          __upsertList(
            {
              id: jsPayload.record!.id,
              createdAt: new Date().toISOString(),
              name: jsPayload.record!.name,
              date: jsPayload.record!.date,
              productAmount: jsPayload.record!.productAmount,
            } as ShoppingList,
            0,
          );

          break;
        }
        case "update":
          __upsertList({
            id: jsPayload.record!.id,
            createdAt: new Date().toISOString(),
            name: jsPayload.record!.name,
            date: jsPayload.record!.date,
          } as ShoppingList);

          break;
        case "delete":
          __deleteList(jsPayload.oldRecord!.id);

          break;
        default:
          throw new Error("Invalid payload");
      }
    } catch (error) {
      console.error(error);
    }
  }

  async function listenForShoppingListsChanges(): Promise<Subscription> {
    if (channel.value.has(channelName.value) && channel.value.get(channelName.value)) {
      shoppingListClient.unsubscribe(channel.value.get(channelName.value)!);
    }

    channel.value.set(
      channelName.value,
      shoppingListClient.listenForShoppingListsChanges(handleChanges),
    );

    return channel.value.get(channelName.value) as Subscription;
  }

  async function addShoppingList(
    params: AddShoppingListParameters,
  ): Promise<Result<ShoppingList, NetworkError>> {
    if (params.name.trim() === "") {
      throw new Error("Nazwa powinna być wypełniona");
    }

    loading.value = true;
    const now = new Date();
    const preparedId = now.valueOf() * 2;
    blockAction(preparedId, "insert");

    __upsertList(
      {
        id: preparedId,
        createdAt: now.toISOString(),
        name: params.name,
        date: new Intl.DateTimeFormat("pl-PL").format(now),
        productAmount: 0,
      } as unknown as ShoppingList,
      0,
    );

    return shoppingListClient
      .createShoppingListAsync(params.name)
      .then((response) => {
        const parsedRes = readResponse<ShoppingList>(response);

        __upsertList(parsedRes, 0, true);
        return response;
      })
      .catch((err) => {
        console.error(err);

        return err;
      })
      .finally(() => {
        loading.value = false;
        releaseAction(preparedId, "insert");
      });
  }

  async function updateShoppingList(
    params: UpdateShoppingListParameters,
  ): Promise<Result<void, NetworkError>> {
    if (params.name?.trim() === "") {
      throw new Error("Nazwa powinna być wypełniona");
    }
    const listToUpdate = __getList(params.id);

    loading.value = true;
    blockAction(params.id, "update");
    __upsertList({ ...params }, listToUpdate.index);

    return shoppingListClient
      .updateShoppingListAsync(BigInt(params.id), params.name, params.date)
      .then((response) => {
        const parsedRes = readResponse<ShoppingList>(response);
        __upsertList(parsedRes, listToUpdate.index);
        return response;
      })
      .catch((err) => {
        console.error(err);
        __upsertList(listToUpdate.item, listToUpdate.index);
        return err;
      })
      .finally(() => {
        loading.value = false;
        releaseAction(params.id, "update");
      });
  }

  async function deleteShoppingList(
    params: DeleteShoppingListParameters,
  ): Promise<Result<EntityId, NetworkError>> {
    const listToDelete = __getList(params.id);

    loading.value = true;
    blockAction(params.id, "delete");

    __deleteList(params.id);

    return shoppingListClient
      .deleteShoppingListAsync(BigInt(params.id))
      .catch((err) => {
        console.error(err);
        __upsertList(listToDelete.item, listToDelete.index);
        return err;
      })
      .finally(() => {
        loading.value = false;
        releaseAction(params.id, "delete");
      });
  }

  onMounted(() => {
    if (toValue(useAutoListenFor)?.includes("shoppingListsChanges")) {
      listenForShoppingListsChanges();
    }
  });

  onUnmounted(() => {
    try {
      channel.value.forEach((subscription) => {
        shoppingListClient.unsubscribe(subscription);
      });
    } catch (e) {
      console.error(e);
    }
  });

  watch(channel, (newDAta) => {
    console.log("useShoppingLists #watch->", newDAta);
  });

  return {
    // State
    shoppingLists: readonly(shoppingLists),
    loading: readonly(computed(() => pending.value || loading.value)),
    error: readonly(computed(() => fetchError.value || error.value)),

    // Actions
    refresh,
    listenForShoppingListsChanges,
    addShoppingList,
    updateShoppingList,
    deleteShoppingList,
    // Utils
  };
}

export interface AddShoppingListParameters {
  name: string;
  date?: string;
}
export interface UpdateShoppingListParameters {
  name?: string;
  id: number;
  date?: string;
}
export interface DeleteShoppingListParameters {
  id: number;
}
